"""
MKT Christ Commentary — Isaiah chapter 49
Run: python3 scripts/zc-christ-isaiah-49.py

Source data used:
- data/interlinear/isaiah.json
- data/translation/draft/mediating/isaiah.json

Key decisions in this range:
- vv. 1-3: Second Servant Song — direct: called from womb, mouth as sword, Israel-identity
- vv. 5-6: light to nations — direct: Luke 2:32; Acts 13:47 (Paul cites v. 6 of Gentile mission)
- v. 7: despised one honored by kings — direct: Phil 2:5-11
- v. 8: given as covenant for the people — direct: Heb 8:6; Luke 22:20
- vv. 15-16: engraved on palms — shadow: John 20:27 (nail-prints in Christ's hands)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Non-destructive merge — existing entries are never overwritten, safe to re-run
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

ISAIAH = {
"49": {
"1": "<p>A direct prophecy. The Servant addresses the coastlands and peoples from afar: <em>YHWH called me from the womb, from the body of my mother he named my name</em>. The pre-birth calling and naming of the Servant — womb-vocation and name-before-birth — is applied directly to Jesus: Luke 1:31 (you shall call his name Jesus); Matthew 1:21 (you shall call his name Jesus, for he will save his people from their sins). The naming before birth is the Incarnation's announcement that the Servant's identity and mission are entirely determined by YHWH, not by circumstance or achievement.</p>",
"2": "<p>A direct prophecy. YHWH made the Servant's mouth like a sharp sword (<em>wayāśem pî kĕḥereb̠ ḥaddāh</em>), hid him in the shadow of his hand, made him a polished arrow, and concealed him in his quiver. The mouth as a sharp sword is applied explicitly to Christ in Revelation 1:16 (from his mouth came a sharp two-edged sword) and 19:15 (from his mouth comes a sharp sword with which to strike down the nations). The concealment in the quiver — the Servant hidden through most of history, prepared and released at the appointed moment — is the mystery of the Incarnation's timing (Gal 4:4: in the fullness of time).</p>",
"3": "<p>A direct prophecy. YHWH says to the Servant: <em>you are my servant, Israel, in whom I will be glorified</em>. The Servant is identified with Israel — yet is distinct from the nation (v. 5: the Servant restores Jacob). Christ is the true Israel: Matthew 2:15 applies Hosea 11:1 (<em>out of Egypt I called my son</em>) to Jesus — the Servant-Israel who undergoes the whole Israel-story in his own person. John 15:1 (I am the true vine) and the <em>I am</em> sayings similarly claim that Jesus is the fulfillment of Israel's symbolic identity. The one in whom YHWH is glorified (John 17:4: I glorified you on earth, having accomplished the work you gave me to do) is the Servant of Isaiah 49:3.</p>",
"4": "<p>A shadow: the Servant's lament — <em>rîq yāga'tî lĕtōhû wĕheb̄el kōḥî killêtî</em> — I have labored in vain; I have spent my strength for nothing and vanity. But my recompense is with YHWH and my reward with my God. The apparent failure of the Servant's mission — labor without visible fruit — is the experience of the cross: the crowds scatter, the disciples flee, the mission appears to end in execution. Yet the Servant's confidence (<em>my recompense is with YHWH</em>) is the faith that underlies Christ's cry on the cross — even in the darkness of Psalm 22:1, the Servant entrusts himself to the Father (Luke 23:46: Father, into your hands I commit my spirit).</p>",
"5": "<p>A direct prophecy. YHWH says: <em>he who formed me from the womb to be his servant, to bring Jacob back to him, and that Israel might be gathered to him</em> — the Servant's first mission is the restoration of Israel. But this is not all. Acts 2:36-41 shows the fulfillment of the first phase: Peter's Pentecost sermon brings three thousand Jews to faith. The regathering of Israel to YHWH through the Servant is the first movement of the gospel, accomplished in Jerusalem before the mission expands outward (Acts 1:8: Jerusalem first, then Judea, Samaria, and the ends of the earth).</p>",
"6": "<p>A direct prophecy. <em>It is too small a thing that you should be my servant to raise up the tribes of Jacob and to restore the survivors of Israel; I will make you as a light for the nations (<em>lĕ'ôr gôyim</em>), that my salvation may reach to the end of the earth.</em> This is one of the most explicit universal-mission texts in the OT. Luke 2:32 quotes it as Simeon applies it to the infant Jesus: <em>a light for revelation to the Gentiles</em>. Acts 13:47 is Paul and Barnabas citing this verse explicitly as their mandate for the Gentile mission: <em>I have made you a light for the Gentiles, that you may bring salvation to the ends of the earth.</em> The Servant's mission is explicitly too large for Israel alone.</p>",
"7": "<p>A direct prophecy. <em>Thus says YHWH, the Redeemer of Israel and his Holy One, to one deeply despised, abhorred by the nation, the servant of rulers</em> — kings shall see and arise, princes shall prostrate themselves. The paradox of the despised Servant honored by kings is the pattern of Philippians 2:5-11: Christ humbles himself to the point of the cross (deeply despised, servant of rulers) — therefore God has highly exalted him and given him the name above every name, so that every knee shall bow. Isaiah 49:7 provides the narrative structure that Paul theologizes in Philippians 2: humiliation followed by universal royal recognition.</p>",
"8": "<p>A direct prophecy. <em>In a time of favor I have answered you; in a day of salvation I have helped you; I will keep you and give you as a covenant for the people</em> (<em>bĕrît 'ām</em>). Paul cites the opening in 2 Corinthians 6:2: <em>behold, now is the favorable time; behold, now is the day of salvation</em> — applying it to the gospel moment. The Servant given as a covenant is the NT's new covenant: Luke 22:20 (this cup is the new covenant in my blood); Hebrews 8:6-13 (Christ is the mediator of a better covenant). The Servant is not merely the messenger of the covenant — he is the covenant itself, the binding tie between YHWH and his people.</p>",
"9": "<p>A shadow: <em>saying to the prisoners, come out; to those who are in darkness, appear</em>. The release of prisoners and those in darkness is the messianic proclamation of Luke 4:18 (the Spirit of the Lord... to proclaim liberty to the captives and recovering of sight to the blind). Peter's liberation from prison (Acts 12:7-11) and Paul's from the Philippian jail (Acts 16:26) are enacted parables of the Servant's prisoner-releasing work. The ultimate liberation is from the prison of sin and death (Heb 2:14-15: Christ delivers those enslaved through the fear of death).</p>",
"10": "<p>A shadow: they shall not hunger or thirst; neither scorching wind nor sun shall strike them — for the one who has compassion on them will lead them, and guide them to springs of water. This is the shepherd-care of the messianic age. Revelation 7:16-17 quotes this verse of the redeemed multitude before the throne: <em>they shall hunger no more, neither thirst anymore; the sun shall not strike them, nor any scorching heat. For the Lamb in the midst of the throne will be their shepherd, and he will guide them to springs of living water</em>. The compassionate guide of Isaiah 49:10 is explicitly identified as the Lamb.</p>",
"11": "<p>A shadow: YHWH turns the mountains into roads, his highways are raised up. The great highway imagery of Isaiah 40:3-4 continues here — the exodus-road made smooth for the returning exiles. The NT applies it to the spread of the gospel: Acts 8 (Philip on the road to Gaza meets the Ethiopian eunuch; the road is the place of conversion); Romans 10:15 (how beautiful are the feet of those who preach good news). The mountain-roads of Isaiah 49:11 are the mission routes of the apostolic church.</p>",
"12": "<p>A shadow: the returnees come from the north, from the west, and from the land of Sinim (the far east). The four-direction return from exile anticipates the eschatological gathering of Matthew 8:11 (many will come from east and west and recline at table with Abraham, Isaac, and Jacob in the kingdom of heaven) and Revelation 7:9 (a great multitude from every nation, tribe, people, and language). The Servant's restored community is gathered from the whole earth, not from one land.</p>",
"13": "<p>A shadow: <em>sing for joy, O heavens! Shout, O earth! Break forth, O mountains, into singing! For YHWH has comforted his people and will have compassion on his afflicted.</em> The cosmic joy at YHWH's comfort is the eschatological register of Revelation 19:1-7 (the great multitude in heaven crying hallelujah, for the Lord reigns). The angels who sang at Christ's birth (Luke 2:13-14) are the first fulfillment of this cosmic praise; the final fulfillment is the new creation's full-throated song. Christ's birth, resurrection, and return all generate this heaven-earth-mountain praise.</p>",
"14": "<p>A revelation of God: Zion says, <em>YHWH has forsaken me; my Lord has forgotten me</em>. The lament of abandonment — the darkest spiritual experience — is voiced by YHWH's chosen city. Christ takes this lament to its absolute extreme: Matthew 27:46 (<em>My God, my God, why have you forsaken me?</em>) — where Zion's complaint becomes the Son's cry from the cross. The divine answer in v. 15-16 is the gospel's answer to the cross's cry of abandonment.</p>",
"15": "<p>A shadow: <em>Can a woman forget her nursing child, that she should have no compassion on the son of her womb? Even these may forget, yet I will not forget you</em>. The nursing-mother image of divine faithfulness establishes that YHWH's compassion is stronger than the strongest human bond. The NT framing: Romans 8:38-39 (nothing in all creation will be able to separate us from the love of God in Christ Jesus our Lord). The God who cannot forget is the God who sent his Son into the very place of forsakenness (v. 14) to ensure that no one who trusts him is ultimately forgotten.</p>",
"16": "<p>A shadow: <em>behold, I have engraved you on the palms of my hands</em> (<em>ḥaqqōtîk̠ 'al-kappāyim</em>). The image of YHWH's people permanently inscribed on his hands is fulfilled in the most concrete way imaginable in the resurrection: John 20:27 (Jesus shows Thomas the nail-marks in his hands and his side — <em>put your finger here and see my hands</em>). The nail-prints in Christ's glorified hands are the eternal engraving of his people on the palms of YHWH's hands. The physical mark of the cross carried into resurrection glory is the fulfillment of Isaiah 49:16.</p>",
"17": "<p>A shadow: your builders come quickly; your destroyers and those who laid you waste go away. The reversal — destroyers flee, builders arrive — is the pattern of the gospel's work in community: Ephesians 2:19-22 (you are built on the foundation of the apostles and prophets, Christ Jesus himself being the cornerstone). The church as the rebuilt Zion, assembled from scattered exiles, is the living fulfillment of the restored city whose builders come quickly.</p>",
"18": "<p>A shadow: lift up your eyes and see — all these gather and come to you. As I live, declares YHWH, you shall put them all on as an ornament; you shall bind them on as a bride does. The adorning of Zion with her returning children — like a bride adorning herself — anticipates Revelation 21:2 (the holy city, the new Jerusalem, coming down out of heaven from God, prepared as a bride adorned for her husband) and 21:9-11 (the Bride, the wife of the Lamb). The adorned Zion of Isaiah 49:18 is the Bride of the Lamb.</p>",
"19": "<p>A revelation of God: the land previously desolate and ruined will now be too cramped for the inhabitants; the devourers will be far away. The abundance-after-desolation pattern is the consistent shape of divine restoration — what appeared irrecoverable becomes overflowing. Paul applies this logic spiritually in 2 Corinthians 4:17 (this light momentary affliction is preparing for us an eternal weight of glory beyond all comparison). The too-crowded city is the NT's picture of the final redeemed community — the vast multitude no one can number (Rev 7:9).</p>",
"20": "<p>A revelation of God: the children born in the time of your bereavement shall yet say, the place is too narrow for me — make room for me to dwell. The children of the bereaved Zion who arrive and fill the land are the Gentile nations who pour into the people of God through the gospel. Paul in Galatians 4:27 quotes Isaiah 54:1 (which develops this same theme) and applies it explicitly: the desolate woman who was childless has more children than the married one. The Gentile multitude fulfills Zion's overcrowded house.</p>",
"21": "<p>A revelation of God: Zion will say, who bore me these? I was bereaved and barren, exiled and put away — who has brought these up? The amazement of the restored Zion at her unexpected children is the amazement of the church at the scope of Gentile inclusion. Romans 9-11 is Paul's extended meditation on this amazement: the surprising addition of the nations to YHWH's people, which Paul calls the mystery hidden for ages (Eph 3:6: the Gentiles are fellow heirs, members of the same body, partakers of the promise in Christ Jesus).</p>",
"22": "<p>A shadow: YHWH will lift up his hand to the nations and raise his signal to the peoples — they shall bring your sons in their arms and carry your daughters on their shoulders. The signal (<em>nēs</em>) lifted to the nations is the messianic banner of Isaiah 11:10,12 and the cross of John 12:32 (<em>when I am lifted up from the earth, I will draw all people to myself</em>). The nations bringing Israel's children in their arms describes the Gentile mission's strange reversal: non-Jews become the carriers of the gospel back to Jewish communities. Acts 15 narrates the beginning of this pattern.</p>",
"23": "<p>A shadow: kings shall be your foster fathers and queens your nursing mothers — they shall bow down to you with face to the earth. The political reversal — kings as nursemaids to Zion — is the pattern of eschatological submission anticipated in Revelation 21:24-26 (the kings of the earth bring their glory into the new Jerusalem). The NT does not allegorize this into purely spiritual terms: Revelation's kings bringing honor to the city is the literal fulfillment of Isaiah 49:23's royal submission.</p>",
"24": "<p>A revelation of God: can the prey be taken from the mighty? Can the captives of the righteous be delivered? The rhetorical question seems to demand a negative answer — no one can take back what a powerful enemy has taken. YHWH's answer in v. 25 reverses it completely. Christ's work is precisely this impossible liberation: Hebrews 2:14-15 (that through death he might destroy the one who has the power of death, the devil, and deliver all those who through fear of death were subject to lifelong slavery). The prey is delivered from the mighty — the impossible rescue accomplished by the cross.</p>",
"25": "<p>A direct promise. <em>Even the captives of the mighty shall be taken, and the prey of the tyrant shall be rescued; for I will contend with those who contend with you, and I will save your children.</em> The divine warrior who contends personally against the oppressor of his people is the theological ground of Christ's warfare against Satan: Colossians 2:15 (he disarmed the rulers and authorities and put them to open shame, triumphing over them in him). 1 John 3:8 (the Son of God appeared to destroy the works of the devil). YHWH who promises to contend with the mighty comes to do it himself in the Son.</p>",
"26": "<p>A direct promise. <em>I will make your oppressors eat their own flesh, and they shall be drunk with their own blood as with wine. Then all flesh shall know that I am YHWH your Savior, and your Redeemer, the Mighty One of Jacob.</em> The universal knowledge of YHWH as Savior and Redeemer — the final outcome of all the battles and reversals — is the eschatological horizon of the gospel: Philippians 2:10-11 (every knee shall bow and every tongue confess that Jesus Christ is Lord, to the glory of God the Father). The <em>all flesh shall know</em> of Isaiah 49:26 is the <em>every tongue shall confess</em> of Philippians 2:11.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'isaiah')
    merge_comm(existing, ISAIAH)
    save_comm('mkt-christ', 'isaiah', existing)
    v = sum(len(vs) for vs in ISAIAH.values())
    print(f'Isaiah 49 mkt-christ: {v} verses written.')

if __name__ == '__main__':
    main()
